import React, { useState, useEffect } from 'react';
import { View, Text, Button, AsyncStorage } from 'react-native';

const TokenGenerator = () => {
  const [token, setToken] = useState(null);

  const generateToken = () => {
    const randomToken = Math.random().toString(36).substr(2, 10);
    setToken(randomToken);
    storeToken(randomToken);
  };

  const storeToken = async (token) => {
    try {
      await AsyncStorage.setItem('offlineToken', token);
    } catch (error) {
      console.log('Error storing token: ', error);
    }
  };

  const loadStoredToken = async () => {
    try {
      const storedToken = await AsyncStorage.getItem('offlineToken');
      if (storedToken) {
        setToken(storedToken);
      }
    } catch (error) {
      console.log('Error loading token: ', error);
    }
  };

  useEffect(() => {
    loadStoredToken();
  }, []);

  return (
    <View>
      <Text>{token ? `Current Token: ${token}` : 'No Token Generated'}</Text>
      <Button title="Generate Token" onPress={generateToken} />
    </View>
  );
};

export default TokenGenerator;